class Solution {
public:
    long long maxGCDScore(vector<int>& nums, int k) {
        int n = nums.size();
        long long maxScore = 0;

        for (int gcd = *max_element(nums.begin(), nums.end()); gcd >= 1; --gcd) {
            int operations = 0;
            long long score = 0;
            for (int i = 0, j = 0; i < n; ++i) {
                if (__gcd(gcd, nums[i]) == gcd) {
                    ++j;
                } else {
                    operations += j & 1;
                    j = 0;
                }
            }
            operations += j & 1;
            if (operations <= k) {
                score = (long long) gcd * n;
                maxScore = max(maxScore, score);
                break;
            }

            for (int i = 0, count = 0; i < n; ++i) {
                if (__gcd(gcd, nums[i] * (i & 1 ? 1 : 2)) == gcd) {
                    ++count;
                }
                if (count >= gcd && (count - gcd) / 2 <= k) {
                    score = (long long) gcd * count;
                    maxScore = max(maxScore, score);
                }
            }
            for (int i = 0, count = 0; i < n; ++i) {
                if (__gcd(gcd, nums[i] * (i & 1 ? 2 : 1)) == gcd) {
                    ++count;
                }
                if (count >= gcd && (count - gcd) / 2 <= k) {
                    score = (long long) gcd * count;
                    maxScore = max(maxScore, score);
                }
            }
        }
        return maxScore;
    }
};
